/** Index of apogee (max XY distance from Earth) in REFERENCE_TRAJECTORY.
 *  Used as the outbound/return split: x is monotonically increasing on
 *  [0, APOGEE_INDEX] and decreasing on [APOGEE_INDEX, end]. */
export const APOGEE_INDEX = 46;

/** cos / sin of the rotation that aligns the Earth → Moon axis (at
 *  closest approach time) with +X. To project a *live* J2000 spacecraft
 *  (or Moon) position into the same frame as REFERENCE_TRAJECTORY:
 *    xn = ( pos.x * PROJECTION_COS + pos.y * PROJECTION_SIN) / MOON_DIST_KM;
 *    yn = (-pos.x * PROJECTION_SIN + pos.y * PROJECTION_COS) / MOON_DIST_KM;
 *  Drops Z — the rendering is a top-down (X-Y) view. */
export const PROJECTION_COS = -0.358512190009;
export const PROJECTION_SIN = -0.933525044985;

/** Normalization scale: |Moon_xy| at apogee, in km.
 *  This is the Moon's XY-projected distance from Earth at closest
 *  approach time, NOT the standard 384,400 km. Multiplying a
 *  REFERENCE_TRAJECTORY x or y value by this constant gives km in the
 *  rotated EME2000 XY frame. The Moon graphic in the panel is drawn at
 *  (1, 0), which corresponds to this distance. */
export const MOON_DIST_KM = 359988;
